{"command": "# Get sorted symbols and find what's near our problem addresses
nm -n /tmp/symbols/libmonosgen-2.0.so.dbg 2>/dev/null | grep -v '\$[dtx]' | awk '
BEGIN { 
  split("0x2f4b20 0x2f4c84", addrs, " ")
  for (i in addrs) targets[addrs[i]] = 1
}
{
  addr = "0x" $1
  if ($2 ~ /[tTwW]/) {
    last_func = $3; last_addr = addr
  }
}
' 
# Simpler: just find symbols near those addresses
nm -n /tmp/symbols/libmonosgen-2.0.so.dbg 2>/dev/null | grep -v '\$[dtx]' | awk '{val=strtonum("0x"$1)} val<=0x2f4b20' | tail -3
echo "---"
nm -n /tmp/symbols/libmonosgen-2.0.so.dbg 2>/dev/null | grep -v '\$[dtx]' | awk '{val=strtonum("0x"$1)} val>0x2f4b20' | head -3
echo "==="
nm -n /tmp/symbols/libmonosgen-2.0.so.dbg 2>/dev/null | grep -v '\$[dtx]' | awk '{val=strtonum("0x"$1)} val<=0x2f4c84' | tail -3
echo "---"
